 35→    'zh-hans': 'zh-cn',
 36→    'zh-hant': 'zh-cn',
 37→    'zh-tw': 'zh-cn',
 38→    'zh-hk': 'zh-cn',
 39→  }
 40→  return mapping[normalized] ?? normalized
 41→}
